/// <summary>
/// Scoped service holding per-circuit theme state.
/// Interactive components subscribe to <see cref="OnChange"/> to re-render
/// when any component mutates the theme.
/// </summary>
public sealed class ThemeService
{
    private Theme _theme = Theme.System;
    private string _accentColor = "#0d6efd"; // Bootstrap primary blue

    public Theme Theme => _theme;
    public string AccentColor => _accentColor;

    /// <summary>
    /// Fired whenever theme or accent color changes.
    /// Subscribers should call StateHasChanged().
    /// </summary>
    public event Action? OnChange;

    public void SetTheme(Theme theme)
    {
        if (_theme == theme) return;
        _theme = theme;
        OnChange?.Invoke();
    }

    public void SetAccentColor(string color)
    {
        if (_accentColor == color) return;
        _accentColor = color;
        OnChange?.Invoke();
    }

    public void SetAll(Theme theme, string accentColor)
    {
        bool changed = _theme != theme || _accentColor != accentColor;
        _theme = theme;
        _accentColor = accentColor;
        if (changed) OnChange?.Invoke();
    }
}

