+@* Quick toggle that can be placed anywhere (e.g. sidebar).
+   Cycles through Light → Dark → System. *@
+@rendermode InteractiveServer
+@implements IDisposable
+@inject ThemeService ThemeSvc
+@inject IJSRuntime JS
+
+<button class="btn btn-sm btn-outline-light theme-toggle" @onclick="CycleTheme" title="Toggle theme">
+    @switch (ThemeSvc.Theme)
+    {
+        case Theme.Light:
+            <span>☀️</span>
+            break;
+        case Theme.Dark:
+            <span>🌙</span>
+            break;
+        case Theme.System:
+            <span>💻</span>
+            break;
+    }
+</button>
+
+@code {
+    protected override void OnInitialized() => ThemeSvc.OnChange += HandleChange;
+
+    protected override async Task OnAfterRenderAsync(bool firstRender)
+    {
+        if (firstRender)
+            await ApplyThemeToDocument();
+    }
+
+    private void CycleTheme()
+    {
+        var next = ThemeSvc.Theme switch
+        {
+            Theme.Light  => Theme.Dark,
+            Theme.Dark   => Theme.System,
+            _            => Theme.Light,
+        };
+        ThemeSvc.SetTheme(next);
+        _ = ApplyThemeToDocument();
+    }
+
+    private async Task ApplyThemeToDocument()
+    {
+        var value = ThemeSvc.Theme switch
+        {
+            Theme.Light => "light",
+            Theme.Dark  => "dark",
+            _           => ""       // System: remove attribute, let OS decide
+        };
+        await JS.InvokeVoidAsync("document.documentElement.setAttribute", "data-bs-theme", value);
+        await JS.InvokeVoidAsync("eval",
+            $"document.documentElement.style.setProperty('--accent-color', '{ThemeSvc.AccentColor}')");
+    }
+
+    private void HandleChange()
+    {
+        _ = InvokeAsync(async () =>
+        {
+            StateHasChanged();
+            await ApplyThemeToDocument();
+        });
+    }
+
+    public void Dispose() => ThemeSvc.OnChange -= HandleChange;
+}
+

