@page "/settings"
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeSvc
@inject IJSRuntime JS

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card mt-3" style="max-width: 480px;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>

        <div class="btn-group mb-3" role="group">
            @foreach (var t in Enum.GetValues<Theme>())
            {
                <button type="button"
                        class="btn @(ThemeSvc.Theme == t ? "btn-primary" : "btn-outline-primary")"
                        @onclick="() => SetTheme(t)">
                    @t
                </button>
            }
        </div>

        <h5 class="card-title">Accent Color</h5>

        <div class="d-flex align-items-center gap-3 mb-3">
            <input type="color" class="form-control form-control-color"
                   value="@ThemeSvc.AccentColor"
                   @onchange="OnAccentChanged"
                   title="Pick accent color" />
            <span class="text-muted">@ThemeSvc.AccentColor</span>
        </div>

        <div class="alert alert-info py-2 mb-0">
            Current: <strong>@ThemeSvc.Theme</strong> &mdash;
            Accent: <span style="color: @ThemeSvc.AccentColor; font-weight: bold;">@ThemeSvc.AccentColor</span>
        </div>
    </div>
</div>

@code {
    protected override void OnInitialized() => ThemeSvc.OnChange += HandleChange;

    private void SetTheme(Theme theme)
    {
        ThemeSvc.SetTheme(theme);
        _ = ApplyThemeToDocument();
    }

    private void OnAccentChanged(ChangeEventArgs e)
    {
        var color = e.Value?.ToString() ?? "#0d6efd";
        ThemeSvc.SetAccentColor(color);
        _ = ApplyThemeToDocument();
    }

    private async Task ApplyThemeToDocument()
    {
        var value = ThemeSvc.Theme switch
        {
            Theme.Light => "light",
            Theme.Dark  => "dark",
            _           => ""
        };
        await JS.InvokeVoidAsync("document.documentElement.setAttribute", "data-bs-theme", value);
        await JS.InvokeVoidAsync("eval",
            $"document.documentElement.style.setProperty('--accent-color', '{ThemeSvc.AccentColor}')");
    }

    private void HandleChange() => InvokeAsync(StateHasChanged);

    public void Dispose() => ThemeSvc.OnChange -= HandleChange;
}

